/* Homepage story-card feed with infinite scroll.
 * Reads feed.json (generated by the publish pipeline) and renders cards in
 * batches as the user scrolls. No framework, no build step. The full,
 * server-rendered archive at /dossiers/ remains the crawlable fallback. */
(function () {
  "use strict";

  var grid = document.getElementById("feed");
  var sentinel = document.getElementById("feed-sentinel");
  var FALLBACK = "./images/mewscast-og.png";
  var BATCH = 24;

  var items = [];
  var rendered = 0;
  var observer = null;

  function esc(s) {
    var d = document.createElement("div");
    d.textContent = s == null ? "" : String(s);
    return d.innerHTML;
  }

  function cardHTML(it) {
    var thumb = it.thumb ? "./" + it.thumb : FALLBACK;
    var conf = (it.confidence != null)
      ? '<span class="confidence">' + esc(it.confidence) + "% confidence</span>"
      : "";
    return (
      '<a class="story-card" href="./' + esc(it.url) + '">' +
        '<div class="story-thumb">' +
          '<img loading="lazy" src="' + esc(thumb) + '" alt="" ' +
            "onerror=\"this.onerror=null;this.src='" + FALLBACK + "'\">" +
        "</div>" +
        '<div class="story-body">' +
          '<div class="story-meta">' +
            '<span class="badge badge-' + esc(it.badge) + '">' + esc(it.post_type) + "</span>" +
            conf +
          "</div>" +
          '<div class="story-headline">' + esc(it.headline) + "</div>" +
          '<div class="story-date">' + esc(it.date_display) + "</div>" +
        "</div>" +
      "</a>"
    );
  }

  function renderBatch() {
    var slice = items.slice(rendered, rendered + BATCH);
    if (!slice.length) return;
    var html = "";
    for (var i = 0; i < slice.length; i++) html += cardHTML(slice[i]);
    grid.insertAdjacentHTML("beforeend", html);
    rendered += slice.length;
    if (rendered >= items.length && observer) {
      observer.disconnect();
      if (sentinel) sentinel.style.display = "none";
    }
  }

  function start() {
    grid.innerHTML = "";  // clear the "Loading…" placeholder
    renderBatch();
    if ("IntersectionObserver" in window && sentinel) {
      observer = new IntersectionObserver(function (entries) {
        for (var i = 0; i < entries.length; i++) {
          if (entries[i].isIntersecting) { renderBatch(); break; }
        }
      }, { rootMargin: "800px" });
      observer.observe(sentinel);
    } else {
      // No IntersectionObserver: render everything at once.
      while (rendered < items.length) renderBatch();
    }
  }

  fetch("./feed.json", { cache: "no-cache" })
    .then(function (r) {
      if (!r.ok) throw new Error("HTTP " + r.status);
      return r.json();
    })
    .then(function (data) {
      items = Array.isArray(data) ? data : [];
      if (!items.length) {
        grid.innerHTML = '<p class="feed-empty">No dossiers published yet.</p>';
        return;
      }
      start();
    })
    .catch(function () {
      grid.innerHTML =
        '<p class="feed-empty">Couldn’t load the feed. ' +
        '<a href="./dossiers/">Browse the full dossier archive →</a></p>';
    });
})();
